ControlPropertyState.AutoRuleBindingString:
Clear(colScannedItems);
Notify("Current scanning session has been cleared.", NotificationType.Warning);
If(App.Mode = AppMode.Run, SetFocus(RapidScanInput));

// Optional: Show a loading spinner
Set(varIsSubmitting, true);

Notify("Submitting inventory updates...", NotificationType.Information);

ForAll(
    colScannedItems, // Loop through every unique item we scanned

    // For each item, check if it already exists in the main 'Inventories' data source
    With(
        {
            existingInventoryItem: LookUp(Inventories, cr31c_cleanedbarcode = ThisRecord.CleanedBarcode)
        },

        If(
            IsBlank(existingInventoryItem),
            // --- CREATE NEW RECORD ---
            Patch(
                Inventories,
                Defaults(Inventories), // Creates a new record
                {
                    cr31c_cleanedbarcode: ThisRecord.CleanedBarcode,
                    cr31c_itemid: ThisRecord.ItemID,
                    cr31c_name: ThisRecord.ProductName,
                    cr31c_manufacturer_lookup: ThisRecord.Manufacturer, // Adjust if this is a lookup column
                    cr31c_batch: ThisRecord.Batch,
                    cr31c_expiration: ThisRecord.Expiration,
                    cr31c_quantity: ThisRecord.Quantity 
                }
            ),

            // --- UPDATE EXISTING RECORD ---
            Patch(
                Inventories,
                existingInventoryItem, // The record to update
                {
                    // Add the scanned quantity to the existing quantity
                    cr31c_quantity: existingInventoryItem.cr31c_quantity + ThisRecord.Quantity
                }
            )
        )
    )
);

// --- CLEANUP AND NOTIFY ---
Clear(colScannedItems); // Clear the local collection for the next session
Set(varIsSubmitting, false); // Hide spinner
Notify("Inventory successfully updated!", NotificationType.Success);
If(App.Mode = AppMode.Run, SetFocus(RapidScanInput));
